24	    https_proxy: config.proxy.http,
25	    HTTP_PROXY: config.proxy.http,
26	    HTTPS_PROXY: config.proxy.http,
27	  };
28	  if (config.proxy.noProxy) {
29	    env.NO_PROXY = config.proxy.noProxy;
30	    env.no_proxy = config.proxy.noProxy;
31	  }
32	  return env;
33	}
34	
35	export function getEcosystemPath(): string {
36	  return ECOSYSTEM_PATH;
37	}
38	
39	/** Generate PM2 ecosystem config content from remi.toml services. */
40	export function generateEcosystem(config: RemiConfig): string {
41	  const apps: Record<string, unknown>[] = [
42	    {
43	      name: "remi",
44	      script: "src/main.ts",
45	      args: "serve",
46	      interpreter: "bun",
47	      cwd: REMI_ROOT,
48	      autorestart: true,
49	      max_restarts: 10,
50	      restart_delay: 3000,
51	      kill_timeout: 15000,
52	      ...(config.proxy.http ? { env: buildProxyEnv(config) } : {}),
53	    },
54	  ];
55	
56	  for (const svc of config.services) {
57	    if (!svc.enabled || !svc.script) continue;
58	    const app: Record<string, unknown> = {
59	      name: svc.name,
60	      script: svc.script,
61	      interpreter: svc.interpreter || "bun",
62	      cwd: svc.cwd,
63	      autorestart: true,
64	      max_restarts: 10,
65	      restart_delay: 2000,
66	    };
67	    if (svc.args.length) app.args = svc.args.join(" ");
68	    const svcEnv: Record<string, unknown> = {};
69	    if (svc.port) svcEnv.PORT = svc.port;
70	    if (config.proxy.http) Object.assign(svcEnv, buildProxyEnv(config));
71	    if (Object.keys(svcEnv).length) app.env = svcEnv;
72	    apps.push(app);
73	  }
74	
75	  return `// Auto-generated by Remi — do not edit manually.\n` +
76	    `module.exports = { apps: ${JSON.stringify(apps, null, 2)} };\n`;
77	}
78	
79	/** Write ecosystem config to ~/.remi/ecosystem.config.cjs. */
80	export function writeEcosystem(config: RemiConfig): string {
81	  const dir = join(homedir(), ".remi");
82	  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
83	  writeFileSync(ECOSYSTEM_PATH, generateEcosystem(config));
84	  return ECOSYSTEM_PATH;
85	}
86	
87	/** Run build commands for all services that have them. */
88	export function runBuildsSync(config: RemiConfig): void {
89	  for (const svc of config.services) {
90	    if (!svc.enabled || !svc.build) continue;
91	    log.info(`Building "${svc.name}": ${svc.build}`);
92	    try {
93	      execSync(svc.build, { cwd: svc.cwd, stdio: "inherit", timeout: 120_000 });
94	      log.info(`Build "${svc.name}" succeeded.`);
95	    } catch (e) {
96	      log.error(`Build "${svc.name}" failed:`, e);
97	    }
98	  }
99	}
100	
101	/** Full PM2 start: generate config → run builds → pm2 start. */
102	export function pm2Start(config: RemiConfig): void {
103	  runBuildsSync(config);
104	  const path = writeEcosystem(config);
105	
106	  log.info("Starting all services with PM2...");
107	  try {
108	    execSync(`pm2 start ${path}`, { stdio: "inherit" });
109	    execSync("pm2 save", { stdio: "inherit" });
110	    log.info("All services started. Run `pm2 status` to check.");
111	  } catch (e) {
112	    log.error("PM2 start failed:", e);
113	    process.exit(1);
114	  }
115	}
116	
117	/** Stop all PM2-managed services. */
118	export function pm2Stop(): void {
119	  try {
120	    execSync("pm2 stop all", { stdio: "inherit" });
121	    log.info("All services stopped.");
122	  } catch (e) {
123	    log.error("PM2 stop failed:", e);
124	  }
125	}
