  google?: GoogleConfig;
  tracing: TracingConfig;
  memoryDir: string;
  pidFile: string;
  logLevel: string;
  contextWarnThreshold: number;
  queueDir: string;
  sessionsFile: string;
}

function defaultProviderConfig(): ProviderConfig {
  return {
    name: "claude_cli",
    fallback: null,
    allowedTools: [],
    model: null,
    timeout: 300,
  };
}

function defaultFeishuConfig(): FeishuConfig {
  return {
    appId: "",
    appSecret: "",
    verificationToken: "",
    encryptKey: "",
    port: 9000,
    domain: "feishu",
    connectionMode: "websocket",
