440	/**
441	 * Get the effective cron jobs list.
442	 * If `config.cronJobs` is populated (new format), use it directly.
443	 * Otherwise, fall back to legacy migration from [scheduler] + [[scheduled_skills]].
444	 */
445	export function migrateToCronJobs(config: RemiConfig): CronJobConfig[] {
446	  if (config.cronJobs.length > 0) {
447	    return config.cronJobs;
448	  }
449	
450	  // Legacy fallback — auto-migrate from old format
451	  return _legacyToCronJobs(config);
452	}
453	
454	function _legacyToCronJobs(config: RemiConfig): CronJobConfig[] {
455	  const jobs: CronJobConfig[] = [];
456	  const compactHour = parseCronHourFromExpr(config.scheduler.memoryCompactCron);
457	
458	  jobs.push(
459	    { id: "builtin:heartbeat", name: "Heartbeat", handler: "builtin:heartbeat", every: `${config.scheduler.heartbeatInterval}s` },
460	    { id: "builtin:compaction", name: "Memory Compaction", handler: "builtin:compaction", cron: config.scheduler.memoryCompactCron },
461	    { id: "builtin:cleanup", name: "Cleanup", handler: "builtin:cleanup", cron: `1 ${compactHour} * * *` },
462	  );
463	
464	  for (const skill of config.scheduledSkills) {
465	    if (!skill.name) continue;
466	    jobs.push({
467	      id: `skill:${skill.name}:gen`, name: `${skill.name} (generate)`,
468	      handler: "skill:gen", enabled: skill.enabled,
469	      cron: `0 ${skill.generateHour} * * *`,
470	      handlerConfig: { skillName: skill.name, outputDir: skill.outputDir },
471	    });
472	    jobs.push({
473	      id: `skill:${skill.name}:push`, name: `${skill.name} (push)`,
474	      handler: "skill:push", enabled: skill.enabled,
475	      cron: `${skill.pushMinute} ${skill.pushHour} * * *`,
476	      handlerConfig: {
477	        skillName: skill.name, outputDir: skill.outputDir,
478	        connectorName: skill.connectorName, pushTargets: skill.pushTargets,
479	        maxPushLength: skill.maxPushLength,
480	      },
481	    });
482	  }
483	
484	  return jobs;
485	}
486	
487	/**
488	 * Write-through migration: rewrite remi.toml from old format to new [[cron.jobs]].
489	 *
490	 * - Detects if old [scheduler] or [[scheduled_skills]] sections exist
491	 * - Converts them to [[cron.jobs]]
492	 * - Removes old sections from the file
493	 * - Backs up the original as remi.toml.bak
494	 *
495	 * Returns true if migration was performed, false if already migrated or no file found.
496	 */
497	export function migrateConfigFile(configPath?: string): boolean {
498	  const filePath = configPath ?? findConfigPath();
499	  if (!filePath) return false;
500	
501	  const raw = readFileSync(filePath, "utf-8");
502	
503	  // Check if already migrated: has [[cron.jobs]] and no [scheduler] or [[scheduled_skills]]
504	  const hasCronJobs = /^\[\[cron\.jobs\]\]/m.test(raw);
505	  const hasScheduler = /^\[scheduler\]/m.test(raw);
506	  const hasScheduledSkills = /^\[\[scheduled_skills\]\]/m.test(raw);
507	
508	  if (hasCronJobs && !hasScheduler && !hasScheduledSkills) {
509	    return false; // Already migrated
510	  }
511	
512	  if (!hasScheduler && !hasScheduledSkills) {
513	    return false; // Nothing to migrate
514	  }
515	
516	  // Parse the old config to get migration data
517	  const config = loadConfig(filePath);
518	  const cronJobs = _legacyToCronJobs(config);
519	
520	  // Backup original
521	  const bakPath = filePath + ".bak";
522	  copyFileSync(filePath, bakPath);
523	
524	  // Remove old sections from raw text and append new [[cron.jobs]]
525	  let newRaw = raw;
526	
527	  // Remove [scheduler] section (header + all subsequent lines until next section header)
528	  newRaw = newRaw.replace(/^\[scheduler\]\r?\n(?:(?!\[)[^\r\n]*\r?\n?)*/gm, "");
529	
530	  // Remove all [[scheduled_skills]] blocks (header + all subsequent lines until next section header)
531	  newRaw = newRaw.replace(/^\[\[scheduled_skills\]\]\r?\n(?:(?!\[)[^\r\n]*\r?\n?)*/gm, "");
532	
533	  // Clean up excessive blank lines
534	  newRaw = newRaw.replace(/\n{3,}/g, "\n\n").trimEnd();
535	
536	  // Build [[cron.jobs]] TOML text
537	  const cronText = buildCronJobsToml(cronJobs);
538	
539	  newRaw += "\n\n# ── Cron Jobs (migrated from [scheduler] + [[scheduled_skills]]) ──\n\n" + cronText;
540	
541	  writeFileSync(filePath, newRaw, "utf-8");
542	  return true;
543	}
544	
545	/**
546	 * Locate the remi.toml config file.
547	 */
548	export function findConfigPath(): string | null {
549	  const candidates = [
550	    join(process.cwd(), CONFIG_FILENAME),
551	    join(homedir(), ".remi", CONFIG_FILENAME),
552	  ];
553	  for (const c of candidates) {
554	    if (existsSync(c)) return c;
555	  }
556	  return null;
557	}
558	
559	/**
560	 * Build TOML text for [[cron.jobs]] entries.
561	 */
562	function buildCronJobsToml(jobs: CronJobConfig[]): string {
563	  const lines: string[] = [];
564	
565	  for (const job of jobs) {
566	    lines.push("[[cron.jobs]]");
567	    lines.push(`id = ${tomlStr(job.id)}`);
568	    if (job.name) lines.push(`name = ${tomlStr(job.name)}`);
569	    lines.push(`handler = ${tomlStr(job.handler)}`);
570	    if (job.enabled === false) lines.push(`enabled = false`);
571	    if (job.cron) lines.push(`cron = ${tomlStr(job.cron)}`);
572	    if (job.tz) lines.push(`tz = ${tomlStr(job.tz)}`);
573	    if (job.every) lines.push(`every = ${tomlStr(String(job.every))}`);
574	    if (job.at) lines.push(`at = ${tomlStr(job.at)}`);
575	    if (job.timeoutMs) lines.push(`timeout_ms = ${job.timeoutMs}`);
576	    if (job.deleteAfterRun) lines.push(`delete_after_run = true`);
577	
578	    // handler_config as a sub-table
579	    if (job.handlerConfig && Object.keys(job.handlerConfig).length > 0) {
580	      lines.push("");
581	      lines.push("[cron.jobs.handler_config]");
582	      for (const [k, v] of Object.entries(job.handlerConfig)) {
583	        const key = k; // Keep camelCase keys as-is to match handler expectations
584	        if (typeof v === "string") {
585	          lines.push(`${key} = ${tomlStr(v)}`);
586	        } else if (typeof v === "number") {
587	          lines.push(`${key} = ${v}`);
588	        } else if (typeof v === "boolean") {
589	          lines.push(`${key} = ${v}`);
590	        } else if (Array.isArray(v)) {
591	          lines.push(`${key} = [${v.map((s) => tomlStr(String(s))).join(", ")}]`);
592	        }
593	      }
594	    }
595	
596	    lines.push("");
597	  }
598	
599	  return lines.join("\n");
600	}
601	
602	function tomlStr(s: string): string {
603	  return `"${s.replace(/\\/g, "\\\\").replace(/"/g, '\\"')}"`;
604	}
605	
606	// ── Bot Menu TOML parsing ────────────────────────────────────
607	
608	function parseBotMenuBehavior(b: Record<string, unknown>): BotMenuBehavior {
609	  return {
610	    type: (b.type as BotMenuBehavior["type"]) ?? "send_message",
611	    url: (b.url as string) ?? undefined,
612	    eventKey: (b.event_key as string) ?? undefined,
613	    isPrimary: (b.is_primary as boolean) ?? undefined,
614	  };
615	}
616	
617	function parseBotMenuIcon(icon: Record<string, unknown>): BotMenuIcon {
618	  return {
619	    token: (icon.token as string) ?? undefined,
620	    color: (icon.color as string) ?? undefined,
621	    fileKey: (icon.file_key as string) ?? undefined,
622	  };
623	}
624	
625	function parseBotMenuItem(item: Record<string, unknown>): BotMenuItemConfig {
626	  const behaviors = (item.behaviors as Array<Record<string, unknown>> | undefined)?.map(parseBotMenuBehavior);
627	  const children = (item.children as Array<Record<string, unknown>> | undefined)?.map(parseBotMenuItem);
628	  const icon = item.icon ? parseBotMenuIcon(item.icon as Record<string, unknown>) : undefined;
629	
630	  return {
631	    name: (item.name as string) ?? "",
632	    i18nName: (item.i18n_name as Record<string, string>) ?? undefined,
633	    icon,
634	    tag: (item.tag as string) ?? undefined,
635	    behaviors,
636	    children,
637	  };
638	}
639	
640	function parseBotMenuConfig(data: Record<string, unknown>): BotMenuConfig {
641	  const defaultItems = (data.default as Array<Record<string, unknown>> | undefined)?.map(parseBotMenuItem);
642	  const usersData = data.users as Array<Record<string, unknown>> | undefined;
643	
644	  const users = usersData?.map((u) => ({
645	    userId: (u.user_id as string) ?? "",
646	    userIdType: (u.user_id_type as BotMenuUserConfig["userIdType"]) ?? "open_id",
647	    label: (u.label as string) ?? undefined,
648	    items: ((u.items as Array<Record<string, unknown>>) ?? []).map(parseBotMenuItem),
649	  }));
650	
651	  return { default: defaultItems, users };
652	}
653	
654	function parseCronHourFromExpr(cronExpr: string): number {
655	  const parts = cronExpr.split(" ");
656	  if (parts.length >= 2) {
657	    const hour = parseInt(parts[1], 10);
658	    if (!isNaN(hour)) return hour;
659	  }
660	  return 3;
661	}
