545	/**
546	 * Locate the remi.toml config file.
547	 */
548	export function findConfigPath(): string | null {
549	  const candidates = [
550	    join(process.cwd(), CONFIG_FILENAME),
551	    join(homedir(), ".remi", CONFIG_FILENAME),
552	  ];
553	  for (const c of candidates) {
554	    if (existsSync(c)) return c;
555	  }
556	  return null;
557	}
558	
559	/**
560	 * Build TOML text for [[cron.jobs]] entries.
561	 */
562	function buildCronJobsToml(jobs: CronJobConfig[]): string {
563	  const lines: string[] = [];
564	
565	  for (const job of jobs) {
566	    lines.push("[[cron.jobs]]");
567	    lines.push(`id = ${tomlStr(job.id)}`);
568	    if (job.name) lines.push(`name = ${tomlStr(job.name)}`);
569	    lines.push(`handler = ${tomlStr(job.handler)}`);
570	    if (job.enabled === false) lines.push(`enabled = false`);
571	    if (job.cron) lines.push(`cron = ${tomlStr(job.cron)}`);
572	    if (job.tz) lines.push(`tz = ${tomlStr(job.tz)}`);
573	    if (job.every) lines.push(`every = ${tomlStr(String(job.every))}`);
574	    if (job.at) lines.push(`at = ${tomlStr(job.at)}`);
575	    if (job.timeoutMs) lines.push(`timeout_ms = ${job.timeoutMs}`);
576	    if (job.deleteAfterRun) lines.push(`delete_after_run = true`);
577	
578	    // handler_config as a sub-table
579	    if (job.handlerConfig && Object.keys(job.handlerConfig).length > 0) {
580	      lines.push("");
581	      lines.push("[cron.jobs.handler_config]");
582	      for (const [k, v] of Object.entries(job.handlerConfig)) {
583	        const key = k; // Keep camelCase keys as-is to match handler expectations
584	        if (typeof v === "string") {
585	          lines.push(`${key} = ${tomlStr(v)}`);
586	        } else if (typeof v === "number") {
587	          lines.push(`${key} = ${v}`);
588	        } else if (typeof v === "boolean") {
589	          lines.push(`${key} = ${v}`);
590	        } else if (Array.isArray(v)) {
591	          lines.push(`${key} = [${v.map((s) => tomlStr(String(s))).join(", ")}]`);
592	        }
593	      }
594	    }
595	
596	    lines.push("");
597	  }
598	
599	  return lines.join("\n");
600	}
601	
602	function tomlStr(s: string): string {
603	  return `"${s.replace(/\\/g, "\\\\").replace(/"/g, '\\"')}"`;
604	}
