138	/**
139	 * cli-ingest — Harvest Claude Code CLI conversations (~/.claude/projects/*)
140	 * and feed them into memory-extract for projects that Remi already knows.
141	 *
142	 * Opt-in rule: only process JSONLs whose cwd has a bootstrapped
143	 * `~/.remi/projects/{hash}/` directory. Projects Remi hasn't been
144	 * introduced to are ignored entirely for privacy.
145	 *
146	 * Per-JSONL cursor (last_pair_count) tracks how much we've already
147	 * processed so each new round is ingested exactly once.
148	 */
149	handlers.set("cli-ingest", async (remi) => {
150	  const { getDb } = await import("../../db/index.js");
151	  const { parseSessionPairs } = await import("../../conversation/parser.js");
152	  const db = getDb();
153	
154	  db.exec(`CREATE TABLE IF NOT EXISTS cli_ingest_cursor (
155	    jsonl_path TEXT PRIMARY KEY,
156	    last_pair_count INTEGER NOT NULL DEFAULT 0,
157	    last_ingested_at TEXT NOT NULL
158	  )`);
159	
160	  const projectsDir = join(homedir(), ".claude", "projects");
161	  if (!existsSync(projectsDir)) {
162	    log.debug("[cli-ingest] ~/.claude/projects not found, skipping");
163	    return;
164	  }
165	
166	  // Only consider JSONLs modified in the last 3 hours — keeps scan fast
167	  const cutoffMs = Date.now() - 3 * 3600 * 1000;
168	  let ingested = 0;
169	  let skippedNoOptIn = 0;
170	  let skippedInactive = 0;
171	
172	  // Use plain readdir + statSync: ~/.claude/projects/ entries are often
173	  // symlinks into ~/.remi/projects/, which Dirent.isDirectory() would skip.
174	  for (const name of readdirSync(projectsDir)) {
175	    const projDir = join(projectsDir, name);
176	    let projStat;
177	    try { projStat = statSync(projDir); } catch { continue; }
178	    if (!projStat.isDirectory()) continue;
179	
180	    for (const file of readdirSync(projDir)) {
181	      if (!file.endsWith(".jsonl")) continue;
182	      const jsonlPath = join(projDir, file);
183	
184	      let stat;
185	      try { stat = statSync(jsonlPath); } catch { continue; }
186	      if (!stat.isFile()) continue;
187	      if (stat.mtimeMs < cutoffMs) { skippedInactive++; continue; }
188	
189	      // Extract cwd — scan first ~20 lines (line 1 is often file-history-snapshot,
190	      // cwd lives on the first user/assistant message line).
191	      let cwd: string | undefined;
192	      try {
193	        const head = readFileSync(jsonlPath, "utf-8", { flag: "r" }).slice(0, 16384);
194	        const lines = head.split("\n", 20);
195	        for (const line of lines) {
196	          if (!line.trim()) continue;
197	          try {
198	            const obj = JSON.parse(line);
199	            if (typeof obj.cwd === "string" && obj.cwd) { cwd = obj.cwd; break; }
200	          } catch { /* skip malformed line */ }
201	        }
202	      } catch { continue; }
203	      if (!cwd) continue;
204	
205	      // Skip agent cwds — these are Remi's own background-agent runs
206	      // (memory-extract, memory-audit, wiki-curate). Ingesting them would
207	      // create a feedback loop: agent run → JSONL → cli-ingest → agent run.
208	      if (/\/agents\/[^/]+\/?$/.test(cwd)) { skippedNoOptIn++; continue; }
209	
210	      // Opt-in: Remi must already know this project
211	      const projectHash = cwd.replace(/\//g, "-");
212	      const remiProjectDir = join(homedir(), ".remi", "projects", projectHash);
213	      if (!existsSync(remiProjectDir)) { skippedNoOptIn++; continue; }
214	
215	      const sessionId = basename(file, ".jsonl");
216	      let pairs;
217	      try {
218	        pairs = parseSessionPairs(jsonlPath, sessionId);
219	      } catch (e) {
220	        log.warn(`[cli-ingest] parse failed for ${sessionId}: ${e}`);
221	        continue;
222	      }
223	
224	      const cursor = db
225	        .query<{ last_pair_count: number }, [string]>(
226	          "SELECT last_pair_count FROM cli_ingest_cursor WHERE jsonl_path = ?",
227	        )
228	        .get(jsonlPath);
229	      const lastCount = cursor?.last_pair_count ?? 0;
230	      if (pairs.length <= lastCount) continue;
231	
232	      const newPairs = pairs.slice(lastCount);
233	      const parts: string[] = [];
234	      for (const p of newPairs) {
235	        if (p.userText) parts.push(`User: ${p.userText.slice(0, 500)}`);
236	        if (p.remiText) parts.push(`Remi: ${p.remiText.slice(0, 500)}`);
237	      }
238	      const aggregatedText = parts.join("\n\n").slice(0, 8000);
239	      if (!aggregatedText) continue;
240	
241	      const contentHash = createHash("sha256")
242	        .update(`${jsonlPath}:${lastCount}:${pairs.length}`)
243	        .digest("hex")
244	        .slice(0, 16);
245	
246	      await remi.queue.enqueueMemory({
247	        sessionKey: `cli-ingest:${sessionId}`,
248	        aggregatedText,
249	        contentHash,
250	        roundCount: newPairs.length,
251	        timestamp: new Date().toISOString(),
252	        cwd,
253	      });
254	
255	      db.query(
256	        "INSERT OR REPLACE INTO cli_ingest_cursor(jsonl_path, last_pair_count, last_ingested_at) VALUES (?, ?, ?)",
257	      ).run(jsonlPath, pairs.length, new Date().toISOString());
258	
259	      ingested++;
260	      log.info(
261	        `[cli-ingest] ${sessionId}: +${newPairs.length} pairs (cwd=${cwd}, total=${pairs.length})`,
262	      );
263	    }
264	  }
265	
266	  log.info(
267	    `[cli-ingest] done — ingested=${ingested}, skipped_no_optin=${skippedNoOptIn}, skipped_inactive=${skippedInactive}`,
268	  );
269	});
