672	      handler,
673	      status,
674	      durationMs,
675	      ...(error && { error: error.slice(0, 500) }),
676	      ...(runId && { runId }),
677	      ...(phase && { phase }),
678	    });
679	    appendFileSync(join(runsDir, `${safeId}.jsonl`), entry + "\n", "utf-8");
680	  } catch {
681	    // non-critical, don't let logging failure break cron
682	  }
683	}
