255	      db.query(
256	        "INSERT OR REPLACE INTO cli_ingest_cursor(jsonl_path, last_pair_count, last_ingested_at) VALUES (?, ?, ?)",
257	      ).run(jsonlPath, pairs.length, new Date().toISOString());
