648	  const selfLogged = handler === "skill:run"; // skill:run logs its own phases
649	  const config = selfLogged ? { ...handlerConfig, _jobId: jobId } : handlerConfig;
650	  const start = Date.now();
651	  try {
652	    await fn(remi, config);
653	    const durationMs = Date.now() - start;
654	    log.info(`Cron job ${jobId} completed in ${durationMs}ms`);
655	    if (!selfLogged) appendRunLog(jobId, handler, "ok", durationMs);
656	  } catch (e) {
657	    const durationMs = Date.now() - start;
658	    log.error(`Cron job ${jobId} failed after ${durationMs}ms:`, e);
659	    if (!selfLogged) appendRunLog(jobId, handler, "error", durationMs, String(e));
660	    throw e; // re-throw so BunQueue records failure + retries
661	  }
